import{_ as e,o as t,c as a,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Session Persistence and Checkpointing in Coding Agents","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/context-management/session-persistence.md","filePath":"research/concepts/context-management/session-persistence.md"}'),o={name:"research/concepts/context-management/session-persistence.md"};function r(i,s,l,p,c,d){return t(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="session-persistence-and-checkpointing-in-coding-agents" tabindex="-1">Session Persistence and Checkpointing in Coding Agents <a class="header-anchor" href="#session-persistence-and-checkpointing-in-coding-agents" aria-label="Permalink to &quot;Session Persistence and Checkpointing in Coding Agents&quot;">​</a></h1><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>Context management doesn&#39;t end when the session closes. The most sophisticated coding agents maintain state across sessions — preserving conversation history, tool call results, modified file lists, and task progress so that work can be resumed without starting from scratch.</p><p>Session persistence sits at a fascinating intersection of concerns. Agents aggressively compact context windows to stay within token limits, discarding older messages and summarizing outputs. But persistence mechanisms want to retain <em>everything</em> — the full history of what happened, what was tried, and what succeeded. This <strong>persistence-context tension</strong> is one of the defining architectural challenges in modern coding agents.</p><p>The approaches vary dramatically. Some use SQLite databases with ACID transactions. Others append JSON events to flat files. Gemini CLI maintains a shadow git repository, auto-committing after each turn. And the most ambitious systems persist conversations across devices and teams.</p><hr><h2 id="_2-sqlite-for-agent-state-opencode-deep-dive" tabindex="-1">2. SQLite for Agent State (OpenCode Deep-Dive) <a class="header-anchor" href="#_2-sqlite-for-agent-state-opencode-deep-dive" aria-label="Permalink to &quot;2. SQLite for Agent State (OpenCode Deep-Dive)&quot;">​</a></h2><p>OpenCode stores ALL conversation data in SQLite within the project directory (<code>.opencode/state.db</code>).</p><h3 id="full-schema" tabindex="-1">Full Schema <a class="header-anchor" href="#full-schema" aria-label="Permalink to &quot;Full Schema&quot;">​</a></h3><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> sessions</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    title </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#A6E3A1;"> &#39;&#39;</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    message_count </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    prompt_tokens </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    completion_tokens </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    summary_message_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    cost </span><span style="color:#CBA6F7;">REAL</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#FAB387;"> 0</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    created_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">),</span></span>
<span class="line"><span style="color:#CDD6F4;">    updated_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">CREATE</span><span style="color:#CBA6F7;"> TABLE</span><span style="color:#89B4FA;font-style:italic;"> messages</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CDD6F4;">    id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> PRIMARY KEY</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    session_id </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> REFERENCES</span><span style="color:#CBA6F7;"> sessions</span><span style="color:#CDD6F4;">(id),</span></span>
<span class="line"><span style="color:#CBA6F7;">    role</span><span style="color:#CBA6F7;"> TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    parts </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CDD6F4;">,  </span><span style="color:#6C7086;font-style:italic;">-- JSON-serialized ContentPart array</span></span>
<span class="line"><span style="color:#CDD6F4;">    model </span><span style="color:#CBA6F7;">TEXT</span><span style="color:#CDD6F4;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    created_at </span><span style="color:#CBA6F7;">INTEGER</span><span style="color:#CBA6F7;"> NOT NULL</span><span style="color:#CBA6F7;"> DEFAULT</span><span style="color:#CDD6F4;"> (unixepoch</span><span style="color:#9399B2;">()</span><span style="color:#CDD6F4;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">);</span></span></code></pre></div><h3 id="schema-design-decisions" tabindex="-1">Schema Design Decisions <a class="header-anchor" href="#schema-design-decisions" aria-label="Permalink to &quot;Schema Design Decisions&quot;">​</a></h3><ul><li><strong><code>parts TEXT NOT NULL</code></strong>: Content stored as JSON-serialized <code>ContentPart</code> array, preserving full structure of multi-modal messages (tool calls, results, images, text blocks).</li><li><strong><code>summary_message_id TEXT</code></strong>: The critical compaction integration field. Marks the boundary — messages before the referenced message have been summarized and can be excluded on restore.</li><li><strong>Token and cost tracking</strong>: <code>prompt_tokens</code>, <code>completion_tokens</code>, and <code>cost</code> tracked at session level, enabling cost accounting without re-parsing message content.</li><li><strong>Unix epoch timestamps</strong>: <code>unixepoch()</code> enables efficient range queries and sorting.</li></ul><h3 id="key-query-patterns" tabindex="-1">Key Query Patterns <a class="header-anchor" href="#key-query-patterns" aria-label="Permalink to &quot;Key Query Patterns&quot;">​</a></h3><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">-- Resume a session: get messages after the summary boundary</span></span>
<span class="line"><span style="color:#CBA6F7;">SELECT</span><span style="color:#94E2D5;"> *</span><span style="color:#CBA6F7;"> FROM</span><span style="color:#CDD6F4;"> messages</span></span>
<span class="line"><span style="color:#CBA6F7;">WHERE</span><span style="color:#CDD6F4;"> session_id </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> ? </span><span style="color:#CBA6F7;">AND</span><span style="color:#CDD6F4;"> created_at </span><span style="color:#94E2D5;">&gt;=</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CBA6F7;">    SELECT</span><span style="color:#CDD6F4;"> created_at </span><span style="color:#CBA6F7;">FROM</span><span style="color:#CDD6F4;"> messages </span><span style="color:#CBA6F7;">WHERE</span><span style="color:#CDD6F4;"> id </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> (</span></span>
<span class="line"><span style="color:#CBA6F7;">        SELECT</span><span style="color:#CDD6F4;"> summary_message_id </span><span style="color:#CBA6F7;">FROM</span><span style="color:#CBA6F7;"> sessions</span><span style="color:#CBA6F7;"> WHERE</span><span style="color:#CDD6F4;"> id </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> ?</span></span>
<span class="line"><span style="color:#CDD6F4;">    )</span></span>
<span class="line"><span style="color:#CDD6F4;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">ORDER BY</span><span style="color:#CDD6F4;"> created_at;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">-- Session listing with cost summary</span></span>
<span class="line"><span style="color:#CBA6F7;">SELECT</span><span style="color:#CDD6F4;"> id, title, message_count, cost, created_at</span></span>
<span class="line"><span style="color:#CBA6F7;">FROM</span><span style="color:#CBA6F7;"> sessions</span><span style="color:#CBA6F7;"> ORDER BY</span><span style="color:#CDD6F4;"> updated_at </span><span style="color:#CBA6F7;">DESC</span><span style="color:#CDD6F4;">;</span></span></code></pre></div><h3 id="why-sqlite" tabindex="-1">Why SQLite <a class="header-anchor" href="#why-sqlite" aria-label="Permalink to &quot;Why SQLite&quot;">​</a></h3><ul><li><strong>Zero configuration</strong>: No database server to install or manage</li><li><strong>Single-file portability</strong>: Entire database in one file, trivially backed up</li><li><strong>ACID transactions</strong>: Safe concurrent reads/writes, crash-resistant</li><li><strong>Universal support</strong>: Every major language has SQLite bindings</li></ul><p>Aider also uses SQLite indirectly through <code>diskcache</code> for repository map tag caching with <code>mtime</code> invalidation — a different use case but the same embedded-database pattern.</p><hr><h2 id="_3-file-based-session-dumps" tabindex="-1">3. File-Based Session Dumps <a class="header-anchor" href="#_3-file-based-session-dumps" aria-label="Permalink to &quot;3. File-Based Session Dumps&quot;">​</a></h2><h3 id="openhands-eventstream" tabindex="-1">OpenHands EventStream <a class="header-anchor" href="#openhands-eventstream" aria-label="Permalink to &quot;OpenHands EventStream&quot;">​</a></h3><p>OpenHands takes an append-only approach inspired by event sourcing:</p><ul><li><strong>EventStream</strong>: Append-only log of all events. Events are never modified or deleted.</li><li><strong>FileStore backend</strong>: Events serialized as JSON, paginated for efficient retrieval.</li><li><strong>Immutable history</strong>: Context management decisions are <em>reversible</em>. Original events persist; only the &quot;view&quot; presented to the LLM changes.</li><li><strong>Reconstruction</strong>: Can reconstruct exactly what the agent saw at any point.</li><li><strong>Event types</strong>: Observations, actions, and agent messages — a complete session record.</li></ul><p>The event sourcing pattern cleanly separates persisted state from runtime state. The EventStream is the source of truth; the condensed context window is a derived view.</p><h3 id="gemini-cli-shadow-git-repository" tabindex="-1">Gemini CLI Shadow Git Repository <a class="header-anchor" href="#gemini-cli-shadow-git-repository" aria-label="Permalink to &quot;Gemini CLI Shadow Git Repository&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>~/.gemini/history/&lt;project_hash&gt;/</span></span>
<span class="line"><span>├── .git/                    # Shadow git repository</span></span>
<span class="line"><span>├── conversation.json        # Full conversation history</span></span>
<span class="line"><span>├── tool_calls.json          # All tool calls and results</span></span>
<span class="line"><span>├── metadata.json            # Session metadata</span></span>
<span class="line"><span>└── files/                   # Snapshots of modified files</span></span></code></pre></div><ul><li><strong>Auto-commit per turn</strong>: Every conversational turn becomes a git commit checkpoint.</li><li><strong>Git-based inspection</strong>: Standard <code>git log</code>, <code>git diff</code>, <code>git show</code> work on history.</li><li><strong>Restore via <code>/restore</code></strong>: Presents checkpoint list, user picks a restore point.</li><li><strong>Leveraging existing infrastructure</strong>: Uses git — a tool developers already understand.</li></ul><h3 id="pi-coding-agent-tree-structured-history" tabindex="-1">Pi Coding Agent Tree-Structured History <a class="header-anchor" href="#pi-coding-agent-tree-structured-history" aria-label="Permalink to &quot;Pi Coding Agent Tree-Structured History&quot;">​</a></h3><p>Pi uses JSONL with <code>id</code> and <code>parentId</code> fields forming a <strong>tree structure</strong>:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">{</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;msg_001&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">parentId</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> null</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;user&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Fix the auth bug&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">{</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;msg_002&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">parentId</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;msg_001&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Looking...&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">{</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;msg_003&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">parentId</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;msg_002&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Found it...&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#9399B2;">{</span><span style="color:#9399B2;">&quot;</span><span style="color:#89B4FA;">id</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;msg_004&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">parentId</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;msg_001&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;assistant&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> &quot;</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;Alternative...&quot;</span><span style="color:#9399B2;">}</span></span></code></pre></div><p>Here <code>msg_004</code> branches from <code>msg_001</code>, creating an alternative path without deleting the original chain. Features include <code>/tree</code> navigation and <code>/fork</code> without history loss. This maps naturally to how developers work — trying approaches, backing up, trying another.</p><hr><h2 id="_4-conversation-checkpointing" tabindex="-1">4. Conversation Checkpointing <a class="header-anchor" href="#_4-conversation-checkpointing" aria-label="Permalink to &quot;4. Conversation Checkpointing&quot;">​</a></h2><p>Checkpointing goes beyond persistence. It creates named, restorable snapshots that users can navigate between.</p><h3 id="claude-code-s-approach" tabindex="-1">Claude Code&#39;s Approach <a class="header-anchor" href="#claude-code-s-approach" aria-label="Permalink to &quot;Claude Code&#39;s Approach&quot;">​</a></h3><ul><li><strong>Session naming</strong>: <code>--name &quot;feature-auth&quot;</code> for human-readable identifiers</li><li><strong>Resume</strong>: <code>--resume</code> continues last session; <code>--resume &quot;feature-auth&quot;</code> for named</li><li><strong>State scope</strong>: Conversation history, modified files list, task progress</li><li><strong>Persistence</strong>: Sessions survive process termination and system restarts</li></ul><h3 id="gemini-cli-s-git-based-checkpointing" tabindex="-1">Gemini CLI&#39;s Git-Based Checkpointing <a class="header-anchor" href="#gemini-cli-s-git-based-checkpointing" aria-label="Permalink to &quot;Gemini CLI&#39;s Git-Based Checkpointing&quot;">​</a></h3><ul><li><strong>Every turn = git commit</strong>: Fine-grained restore points without explicit user action</li><li><strong><code>/restore</code> workflow</strong>: Checkpoint list with timestamps, user picks restore point</li><li><strong>Undo semantics</strong>: Like &quot;undo&quot; for the entire conversation</li><li><strong>Diffable</strong>: Inspect changes between checkpoints with <code>git diff</code></li></ul><h3 id="warp-drive" tabindex="-1">Warp Drive <a class="header-anchor" href="#warp-drive" aria-label="Permalink to &quot;Warp Drive&quot;">​</a></h3><ul><li><strong>Cross-device persistence</strong>: Conversations sync across devices via cloud storage</li><li><strong>Team-shared sessions</strong>: Conversations shared with team members</li><li><strong><code>/fork-and-compact</code></strong>: New conversation branch with compacted history</li><li><strong>Persistent team knowledge</strong>: Solutions discovered by one member accessible to others</li></ul><h3 id="droid-s-cross-interface-persistence" tabindex="-1">Droid&#39;s Cross-Interface Persistence <a class="header-anchor" href="#droid-s-cross-interface-persistence" aria-label="Permalink to &quot;Droid&#39;s Cross-Interface Persistence&quot;">​</a></h3><ul><li><strong>Interface-agnostic</strong>: Single conversation spans web, CLI, GitHub, and Slack</li><li><strong>Unified state</strong>: Same session identity regardless of interface</li><li><strong>Transition continuity</strong>: Switching interfaces doesn&#39;t lose state</li></ul><p>This is the most challenging architecture — requires centralized session store with real-time synchronization accessible from multiple clients.</p><hr><h2 id="_5-resume-from-checkpoint-patterns" tabindex="-1">5. Resume from Checkpoint Patterns <a class="header-anchor" href="#_5-resume-from-checkpoint-patterns" aria-label="Permalink to &quot;5. Resume from Checkpoint Patterns&quot;">​</a></h2><ul><li><strong>Full restore</strong>: Load entire conversation history, replay from beginning. Simple but impractical for long sessions that would exceed token limits.</li><li><strong>Summary restore</strong>: Load summary message + messages after summary (OpenCode&#39;s approach via <code>summary_message_id</code>). Solves token limits while preserving continuity.</li><li><strong>Selective restore</strong>: User chooses which checkpoint to resume from (Gemini CLI). Maximum flexibility but requires user to understand checkpoint history.</li></ul><h3 id="the-cold-start-problem" tabindex="-1">The Cold-Start Problem <a class="header-anchor" href="#the-cold-start-problem" aria-label="Permalink to &quot;The Cold-Start Problem&quot;">​</a></h3><p>After restore, the agent faces &quot;cold start&quot; — it has history but may lack implicit context accumulated during the original session. Agents handle this differently:</p><ul><li><strong>Claude Code</strong>: Re-reads <code>CLAUDE.md</code> on every session start, ensuring project context is always available regardless of conversation history.</li><li><strong>OpenCode</strong>: Summary message is designed to capture essential context, but subtle understanding may be lost.</li><li><strong>Gemini CLI</strong>: Full checkpoint includes file snapshots, so the agent can re-examine codebase state at the checkpoint rather than current state.</li></ul><hr><h2 id="_6-checkpoint-storage-strategies" tabindex="-1">6. Checkpoint Storage Strategies <a class="header-anchor" href="#_6-checkpoint-storage-strategies" aria-label="Permalink to &quot;6. Checkpoint Storage Strategies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strategy</th><th>Queryable</th><th>Versioned</th><th>Portable</th><th>Complexity</th><th>Best For</th></tr></thead><tbody><tr><td>SQLite</td><td>✅</td><td>No</td><td>✅</td><td>Low</td><td>Single-agent, structured data</td></tr><tr><td>JSON/JSONL</td><td>Limited</td><td>No</td><td>✅</td><td>Lowest</td><td>Simple persistence</td></tr><tr><td>Git</td><td>Via diff</td><td>✅</td><td>✅</td><td>Medium</td><td>Checkpoint/restore workflows</td></tr><tr><td>Cloud</td><td>✅</td><td>Varies</td><td>✅✅</td><td>High</td><td>Team collaboration</td></tr></tbody></table><p><strong>SQLite</strong>: Best for structured queries over session metadata. Single-file, no infrastructure. Limitation: no built-in versioning.</p><p><strong>JSON/JSONL</strong>: Best for simplicity and human readability. JSONL suits append-only patterns. Limitation: query efficiency degrades with large histories.</p><p><strong>Git</strong>: Best when checkpoint/restore is primary workflow. Free versioning and diffing. Limitation: storage efficiency — git isn&#39;t designed for large JSON blobs.</p><p><strong>Cloud</strong>: Best for team collaboration and cross-device use. Limitation: complexity, privacy concerns (data leaves local machine).</p><hr><h2 id="_7-multi-session-management" tabindex="-1">7. Multi-Session Management <a class="header-anchor" href="#_7-multi-session-management" aria-label="Permalink to &quot;7. Multi-Session Management&quot;">​</a></h2><p>As agents accumulate sessions, management becomes its own challenge:</p><ul><li><strong>Session listing</strong>: Metadata display (title, timestamps, message count, cost) helps users find the right session without remembering arbitrary IDs.</li><li><strong>Session naming</strong>: Named sessions (Claude Code&#39;s <code>--name</code>) are valuable for long tasks. Common patterns: feature branch names, ticket numbers, task descriptions.</li><li><strong>Cleanup and archival</strong>: Agents rarely implement automatic cleanup. Better approaches would include age-based archival, cost-based retention, or git-branch-linked lifecycle.</li><li><strong>Cost tracking</strong>: OpenCode&#39;s per-session cost tracking enables queries like &quot;how much did feature X cost?&quot; — increasingly important as LLM costs become budget line items.</li></ul><hr><h2 id="_8-the-persistence-context-tension" tabindex="-1">8. The Persistence-Context Tension <a class="header-anchor" href="#_8-the-persistence-context-tension" aria-label="Permalink to &quot;8. The Persistence-Context Tension&quot;">​</a></h2><p>The fundamental tension: compaction discards information to free context space, but persistence wants to retain everything. Agents resolve this differently:</p><h3 id="goose-visibility-flags" tabindex="-1">Goose: Visibility Flags <a class="header-anchor" href="#goose-visibility-flags" aria-label="Permalink to &quot;Goose: Visibility Flags&quot;">​</a></h3><p><code>agent_visible: false</code> makes messages invisible to the LLM but preserved in persisted history. Cleanly separates &quot;what the LLM sees&quot; from &quot;what is stored.&quot;</p><h3 id="openhands-immutable-eventstream-condensed-view" tabindex="-1">OpenHands: Immutable EventStream + Condensed View <a class="header-anchor" href="#openhands-immutable-eventstream-condensed-view" aria-label="Permalink to &quot;OpenHands: Immutable EventStream + Condensed View&quot;">​</a></h3><p>Two parallel representations: the immutable EventStream (complete history) and the condensed view (LLM-visible subset). Context management only affects the view. Any condensation decision is reversible.</p><h3 id="codex-ghostsnapshot-items" tabindex="-1">Codex: GhostSnapshot Items <a class="header-anchor" href="#codex-ghostsnapshot-items" aria-label="Permalink to &quot;Codex: GhostSnapshot Items&quot;">​</a></h3><p><code>GhostSnapshot</code> items are preserved through compaction cycles — references to previous states enabling undo/redo even after context has been compacted. Invisible to the LLM during normal generation, materializable when needed for state restoration.</p><h3 id="mini-swe-agent-no-compaction" tabindex="-1">mini-SWE-agent: No Compaction <a class="header-anchor" href="#mini-swe-agent-no-compaction" aria-label="Permalink to &quot;mini-SWE-agent: No Compaction&quot;">​</a></h3><p>Never compacts. The saved trajectory exactly matches what the LLM saw, making it directly usable as training data. Sessions must stay within context window limits, but for research and training-data generation, this trade-off is acceptable.</p><hr><h2 id="_9-best-practices" tabindex="-1">9. Best Practices <a class="header-anchor" href="#_9-best-practices" aria-label="Permalink to &quot;9. Best Practices&quot;">​</a></h2><ul><li><p><strong>Separate LLM view from persistent state</strong>: Persisted state should be a superset of the LLM view, never a subset. Enables aggressive context management without sacrificing future restore or analysis capability.</p></li><li><p><strong>Use structured storage for metadata</strong>: Session-level metadata (timestamps, costs, token counts) benefits from SQLite. &quot;Show sessions from last week costing &gt;$1&quot; matters.</p></li><li><p><strong>Implement checkpoint/restore for long tasks</strong>: Any task taking more than a few minutes needs checkpointing. Losing an hour of agent work to an interruption is unacceptable.</p></li><li><p><strong>Track costs per session</strong>: Enables budget management, cost optimization, accountability, and ROI analysis comparing agent-assisted vs. manual development.</p></li><li><p><strong>Consider cross-session learning</strong>: Auto-memory patterns, instruction file updates based on observed patterns, and team knowledge extraction represent the frontier of persistent agent memory.</p></li><li><p><strong>Design for debuggability</strong>: The persistence layer is your forensic tool. Design it to answer: &quot;What did the agent see when it made that decision?&quot; Event sourcing and git-based checkpointing excel here because they preserve complete, ordered history.</p></li></ul><hr><h2 id="_10-summary" tabindex="-1">10. Summary <a class="header-anchor" href="#_10-summary" aria-label="Permalink to &quot;10. Summary&quot;">​</a></h2><p>Session persistence is a surprisingly deep problem space. The simplest approaches — dumping conversation JSON to a file — work for basic use cases but fail to address the persistence-context tension, multi-session management, cost tracking, and collaboration.</p><p>The most sophisticated approaches recognize that persistence and context management are two sides of the same coin. They maintain immutable, complete session histories at the storage layer while presenting compact, optimized views to the LLM. They provide checkpoint/restore workflows that give users control over session navigation. And they track metadata that makes sessions queryable, accountable, and debuggable.</p><p>The trajectory is clear: persistence is evolving from &quot;save the chat log&quot; toward durable, structured, queryable agent memory that spans sessions, devices, and teams. The agents that get persistence right will be the ones that feel like they truly <em>remember</em> — picking up exactly where they left off, retaining lessons learned, and building on past work rather than starting from scratch every time.</p>`,78)])])}const g=e(o,[["render",r]]);export{u as __pageData,g as default};
